    def _vaa_score(self, closes, i, bonus=0.0):
        try:
            if i < 252:
                return None
            p0 = float(closes.iloc[i])
            p1 = float(closes.iloc[i - 21])
            p3 = float(closes.iloc[i - 63])
            p6 = float(closes.iloc[i - 126])
            p12 = float(closes.iloc[i - 252])
            if any(p <= 0 for p in [p0, p1, p3, p6, p12]):
                return None
            score = (12 * (p0 / p1 - 1) +
                     4  * (p0 / p3 - 1) +
                     2  * (p0 / p6 - 1) +
                     1  * (p0 / p12 - 1))
            return score + bonus
        except Exception:
            return None

    def _sma_val(self, closes, i, period):
        try:
            if i < period:
                return None
            return float(closes.iloc[i - period:i].mean())
        except Exception:
            return None

    def _realized_vol(self, closes, i, lookback):
        """Annualized realized vol from daily log returns."""
        try:
            if i < lookback + 1:
                return None
            prices = closes.iloc[i - lookback:i + 1]
            log_rets = np.diff(np.log(prices.values.astype(float)))
            if len(log_rets) < lookback // 2:
                return None
            return float(np.std(log_rets) * np.sqrt(252))
        except Exception:
            return None

